export function SubmitButton(params){
    return (
        <Button {...params} type="submitButton"></Button>
    )
}

export function OptionButton(params, children){
    console.log(children)
    return (
        <Button {...params} type="optionButton">{children}</Button>
    )
}

function Button(params){
    let name = params.name;
    let style = "btn " + params.type;
    return (
        <button className={style} onClick={() => {params.onQuizName(name)}}>{name}</button>
    )
}
